// Extract LINE message event
const body = $input.first().json;
const event = body.events?.[0];
if (!event || event.type !== 'message' || event.message?.type !== 'text') {
  return [{ json: { skip: true } }];
}
return [{
  json: {
    userId: event.source.userId,
    replyToken: event.replyToken,
    text: event.message.text.trim(),
    skip: false
  }
}];

// ─── BabyKawaii LINE Bot — Brain ───────────────────────────────
const msg    = $('🔍 แยก LINE Message').first().json.text.toLowerCase();
const userId = $('🔍 แยก LINE Message').first().json.userId;
const replyToken = $('🔍 แยก LINE Message').first().json.replyToken;
const sessionData = $('💾 โหลด Session').first().json.data;
const state  = $('💾 โหลด Session').first().json.data?.state ?? 'idle';
const cart   = sessionData?.data ?? {};

// Products loaded dynamically (stored in session or fetched fresh)
const products = cart.products ?? [];

let reply = '';
let newState = state;
let newData  = { ...cart };
let createOrder = null;

// ── State machine ────────────────────────────────────────────────
if (state === 'idle') {
  if (msg.match(/สวัสดี|หวัดดี|สั่ง|ซื้อ|สินค้า|ดู|มีอะไร/)) {
    reply = `🌸 สวัสดีครับ ยินดีต้อนรับสู่ BabyKawaii Shop!

พิมพ์ "สินค้า" เพื่อดูรายการสินค้า
พิมพ์ "ออเดอร์" เพื่อตรวจสอบคำสั่งซื้อ
พิมพ์ "ติดต่อ" เพื่อคุยกับเจ้าหน้าที่`;
    newState = 'menu';
  } else {
    reply = `🌸 สวัสดีครับ! พิมพ์ "สินค้า" เพื่อเริ่มช้อปปิ้งนะครับ`;
  }
}
else if (state === 'menu' || msg === 'สินค้า') {
  // Will fetch products in next node — signal with state
  newState = 'choosing_product';
  reply = '__FETCH_PRODUCTS__'; // sentinel
}
else if (state === 'choosing_product') {
  const num = parseInt(msg);
  if (!isNaN(num) && products[num-1]) {
    const p = products[num-1];
    newData = { ...cart, product: p };
    newState = 'choosing_size';
    reply = `เลือก "${p.name}" ราคา ฿${p.price.toLocaleString('th-TH')} ✅

กรุณาเลือกไซต์:
(พิมพ์หมายเลขหรือชื่อไซต์)`;
  } else {
    reply = '❌ กรุณาพิมพ์หมายเลขสินค้าที่ต้องการครับ';
  }
}
else if (state === 'choosing_size') {
  newData = { ...cart, size: msg.toUpperCase() };
  newState = 'choosing_color';
  reply = `ไซต์ ${msg.toUpperCase()} ✅\n\nกรุณาเลือกสี (พิมพ์ชื่อสี):`;
}
else if (state === 'choosing_color') {
  newData = { ...cart, color: msg };
  newState = 'choosing_qty';
  reply = `สี ${msg} ✅\n\nต้องการกี่ชิ้นครับ?`;
}
else if (state === 'choosing_qty') {
  const qty = parseInt(msg);
  if (isNaN(qty) || qty < 1) {
    reply = '❌ กรุณาพิมพ์จำนวนเป็นตัวเลขครับ';
  } else {
    newData = { ...cart, qty };
    newState = 'getting_address';
    const total = (cart.product?.price ?? 0) * qty;
    reply = `${qty} ชิ้น ✅

สรุปออเดอร์:
📦 ${cart.product?.name}
ไซต์: ${cart.size} / สี: ${cart.color}
จำนวน: ${qty} ชิ้น × ฿${cart.product?.price?.toLocaleString('th-TH')}
รวม: ฿${total.toLocaleString('th-TH')}

กรุณาพิมพ์ชื่อและที่อยู่จัดส่ง:
(เช่น: สมชาย ใจดี / 123 ซ.ลาดพร้าว กทม.)`;
  }
}
else if (state === 'getting_address') {
  newData = { ...cart, address: msg };
  newState = 'confirming';
  const total = (cart.product?.price ?? 0) * (cart.qty ?? 1);
  reply = `ที่อยู่: ${msg} ✅

📋 ยืนยันออเดอร์:
${cart.product?.name} ${cart.size}/${cart.color} × ${cart.qty}
รวม: ฿${total.toLocaleString('th-TH')} + ค่าส่ง

พิมพ์ "ยืนยัน" เพื่อสั่งซื้อ
พิมพ์ "ยกเลิก" เพื่อเริ่มใหม่`;
}
else if (state === 'confirming') {
  if (msg === 'ยืนยัน') {
    createOrder = {
      customer_name: cart.address?.split('/')[0]?.trim() ?? 'ลูกค้า LINE',
      customer_phone: '',
      customer_address: cart.address,
      platform: 'line',
      line_user_id: userId,
      notes: 'สั่งผ่าน LINE Bot',
      items: [{
        product_id: cart.product?.id,
        size:  cart.size,
        color: cart.color,
        quantity: cart.qty
      }]
    };
    newState = 'idle';
    newData  = {};
    reply    = '__CREATE_ORDER__'; // handled by order node
  } else if (msg === 'ยกเลิก') {
    newState = 'idle'; newData = {};
    reply = '❌ ยกเลิกออเดอร์แล้วครับ พิมพ์ "สินค้า" เพื่อเริ่มใหม่';
  } else {
    reply = 'พิมพ์ "ยืนยัน" หรือ "ยกเลิก" ครับ';
  }
}

return [{
  json: { userId, replyToken, reply, newState, newData, createOrder }
}];

const orderResp = $input.first().json.data;
return [{ json: { message: `✅ สั่งซื้อสำเร็จ!
เลขออเดอร์: ${orderResp.order_number}
ยอดรวม: ฿${Number(orderResp.total).toLocaleString('th-TH')}

ทางร้านจะติดต่อกลับเพื่อยืนยันและแจ้งเลขพัสดุครับ 🌸` } }];
